var e=e=>{switch(e){case`auth/invalid-api-key`:return`Firebase is not configured for this deployment yet. Add VITE_FIREBASE_* values in GitHub secrets.`;case`auth/configuration-not-found`:return`Firebase Auth configuration is missing. Verify project settings and deployment secrets.`;case`auth/invalid-credential`:return`Invalid email or password.`;case`auth/email-already-in-use`:return`This email is already in use. Try logging in instead.`;case`auth/weak-password`:return`Password is too weak. Please make it stronger.`;case`auth/too-many-requests`:return`Too many attempts. Please wait and try again.`;case`auth/network-request-failed`:return`Network error. Check your internet and retry.`;default:return`Something went wrong. Please try again.`}},t=e=>({minLength:e.length>=8,upperCase:/[A-Z]/.test(e),lowerCase:/[a-z]/.test(e),number:/\d/.test(e),symbol:/[^A-Za-z0-9]/.test(e)}),n=e=>{let n=t(e);return Object.values(n).every(Boolean)};export{e as n,t as r,n as t};